"""
    update_policy_engine(policy_engine_id)
    update_policy_engine(policy_engine_id, params::Dict{String,<:Any})

Updates an existing policy engine within the AgentCore Policy system. This operation allows
modification of the policy engine description while maintaining its identity. This is an
asynchronous operation. Use the [`get_policy_engine`](@ref) operation to poll the `status`
field to track completion.

# Arguments

- `policy_engine_id`: The unique identifier of the policy engine to be updated.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"description"`: The new description for the policy engine.
"""
function update_policy_engine end

function update_policy_engine(
    policyEngineId; aws_config::AbstractAWSConfig=current_aws_config()
)
    return bedrock_agentcore_control(
        "PATCH",
        "/policy-engines/$(policyEngineId)";
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_policy_engine(
    policyEngineId,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return bedrock_agentcore_control(
        "PATCH",
        "/policy-engines/$(policyEngineId)",
        params;
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    update_workload_identity(name)
    update_workload_identity(name, params::Dict{String,<:Any})

Updates an existing workload identity.

# Arguments

- `name`: The name of the workload identity to update.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"allowedResourceOauth2ReturnUrls"`: The new list of allowed OAuth2 return URLs for
  resources associated with this workload identity. This list replaces the existing list.
"""
function update_workload_identity end

function update_workload_identity(name; aws_config::AbstractAWSConfig=current_aws_config())
    return bedrock_agentcore_control(
        "POST",
        "/identities/UpdateWorkloadIdentity",
        Dict{String,Any}("name" => name);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_workload_identity(
    name, params::AbstractDict{String}; aws_config::AbstractAWSConfig=current_aws_config()
)
    return bedrock_agentcore_control(
        "POST",
        "/identities/UpdateWorkloadIdentity",
        Dict{String,Any}(mergewith(_merge, Dict{String,Any}("name" => name), params));
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end
